What does this program print?

```cpp
#include <iostream>

struct Vec2 {
    int x{ 0 };
    int y{ 0 };
};

void scale(Vec2 v, int factor) {
    v.x *= factor;
    v.y *= factor;
    std::cout << v.x << ' ' << v.y << '\n';
}

int main() {
    Vec2 v{ 3, 5 };
    scale(v, 2);
    std::cout << v.x << ' ' << v.y << '\n';
}
```

What does this program print?

```cpp
#include <iostream>

struct Pair {
    int a{ 1 };
    int b{ 2 };
};

Pair swap_pair(Pair p) {
    return Pair{ p.b, p.a };
}

int main() {
    Pair original{ 10, 20 };
    Pair swapped{ swap_pair(original) };
    std::cout << swapped.a << ' ' << swapped.b << '\n';
    std::cout << original.a << ' ' << original.b << '\n';
}
```

The programmer wants `reset` to set the caller's counter back to zero. Spot the bug.

```cpp
#include <iostream>

struct Counter {
    int count{ 0 };
};

void reset(Counter c) {
    c.count = 0;
}

int main() {
    Counter c{ .count = 42 };
    reset(c);
    std::cout << c.count << '\n'; // expected 0
}
```
